    <script>
        const exampleXML = `<story_panel>$1</story_panel>`;

        function parseXML(xml) {
            console.log("双视角面板开始解析...");
            const data = {
                env: { time: '', place: '', weather: '' },
                content: '',
                userOptions: [],
                npcOptions: []
            };

            try {
                // 优化后的正则，防止换行符干扰
                const envMatch = xml.match(/<env_info>([\s\S]*?)<\/env_info>/i);
                if (envMatch) {
                    const text = envMatch[1];
                    data.env.time = text.match(/\[时间\|([^\]]+)\]/)?.[1].trim() || '';
                    data.env.place = text.match(/\[地点\|([^\]]+)\]/)?.[1].trim() || '';
                    data.env.weather = text.match(/\[天气\|([^\]]+)\]/)?.[1].trim() || '';
                }

                const contentMatch = xml.match(/<main_content>([\s\S]*?)<\/main_content>/i);
                if (contentMatch) {
                    // 支持 [正文|...] 和 直接正文 两种格式
                    const innerMatch = contentMatch[1].match(/\[正文\|([\s\S]*)\]/);
                    data.content = innerMatch ? innerMatch[1].trim() : contentMatch[1].trim();
                }

                const optMatch = xml.match(/<choice_options>([\s\S]*?)<\/choice_options>/i);
                if (optMatch) {
                    const allOptions = [];
                    const regex = /\[选项\|([\s\S]*?)\]/g;
                    let match;
                    while ((match = regex.exec(optMatch[1])) !== null) {
                        if (match[1]) allOptions.push(match[1].trim());
                    }
                    data.userOptions = allOptions.slice(0, 4);
                    data.npcOptions = allOptions.slice(4, 8);
                }
                console.log("解析成功:", data);
            } catch (e) {
                console.error("解析错误", e);
                data.content = "解析数据时发生错误：" + e.message;
            }
            return data;
        }

        function setInputText(text) {
            let textarea = document.getElementById('send_textarea');
            if (!textarea && window.parent) {
                try {
                    textarea = window.parent.document.getElementById('send_textarea');
                } catch (e) { console.error("无法访问父级:", e); }
            }

            if (textarea) {
                textarea.value = text;
                textarea.dispatchEvent(new Event('input', { bubbles: true }));
                textarea.dispatchEvent(new Event('change', { bubbles: true }));
                textarea.focus();
            } else {
                navigator.clipboard.writeText(text).then(() => {
                    alert('内容已复制');
                }).catch(() => {
                    alert('请手动输入：' + text);
                });
            }
        }

        function toggleDarkMode() { document.body.classList.toggle('dark-mode'); }
        function toggleWideMode() { document.getElementById('app').classList.toggle('wide-mode'); }

        function toggleFullScreen() {
            const app = document.getElementById('app');
            if (!document.fullscreenElement) {
                app.requestFullscreen().catch(err => alert(err.message));
            } else {
                document.exitFullscreen();
            }
        }

        document.addEventListener('fullscreenchange', () => {
            const app = document.getElementById('app');
            const btn = document.getElementById('fullscreen-btn');
            if (document.fullscreenElement) {
                app.classList.add('fullscreen-mode');
                if(btn) btn.innerHTML = '↘️';
            } else {
                app.classList.remove('fullscreen-mode');
                if(btn) btn.innerHTML = '↗️';
            }
        });

        function render(data) {
            const app = document.getElementById('app');
            let html = `
                <div class="toolbar">
                    <button class="tool-btn" onclick="toggleWideMode()" title="宽屏模式">↔️</button>
                    <button id="fullscreen-btn" class="tool-btn" onclick="toggleFullScreen()" title="全屏模式">↗️</button>
                    <button class="tool-btn" onclick="toggleDarkMode()" title="切换模式">🌙</button>
                </div>
                <div class="info-bar">
                    <div class="info-item">🕒 ${data.env.time || '未知'}</div>
                    <div class="info-item">📍 ${data.env.place || '未知'}</div>
                    <div class="info-item">🌤️ ${data.env.weather || '未知'}</div>
                </div>
                <div class="content-area">${data.content || '(无内容)'}</div>
                <div class="options-area">
            `;

            const renderOpt = (opt, type) => {
                const safeOpt = opt.replace(/'/g, "\\'").replace(/"/g, '&quot;');
                return `<div class="option-btn ${type}" onclick="setInputText('${safeOpt}')">${opt}</div>`;
            };

            data.userOptions.forEach(opt => html += renderOpt(opt, 'user-option'));
            data.npcOptions.forEach(opt => html += renderOpt(opt, 'npc-option'));

            if (!data.userOptions.length && !data.npcOptions.length) {
                 html += `<div style="text-align:center; color:#999; padding:10px;">(无可用选项)</div>`;
            }

            html += `</div>`;
            app.innerHTML = html;
        }

        function init() {
            try {
                const data = parseXML(exampleXML);
                render(data);
            } catch (e) {
                document.getElementById('app').innerHTML = `<div class="loading">❌ 错误：${e.message}</div>`;
            }
        }

        init();
    </script>
</body>
</html>
